<template>
  <v-snackbar
    v-model="snack"
    color="success"
    right
    bottom
    class="fix_snack"
    timeout="2500"
  >
    <template v-slot:action="{ on, attrs }">
      <v-btn
        v-on="on"
        v-bind="attrs"
        @click="
          snack = false;
          A_deleteSnack(id);
        "
        text
      >
        <v-icon>mdi-close</v-icon>
      </v-btn>
    </template>
    <span>added to cart</span>
  </v-snackbar>
</template>

<script>
import { mapActions } from "vuex";
export default {
  props: ["id"],
  data() {
    return {
      snack: true,
    };
  },
  methods: {
    ...mapActions(["A_deleteSnack"]),
  },
};
</script>

